#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
混合策略模拟盘盘后自动更新
- 交易日 15:00-17:00 窗口内运行
- 每日仅运行一次
- 更新完成后输出 JSON（供 cron/feishu 推送）
"""
import argparse, json, os, re, subprocess, sys
from datetime import datetime
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]
SIM_DIR = ROOT / "simulation"
STATE_FILE = SIM_DIR / "paper_state.json"


def now_shanghai() -> datetime:
    return datetime.now()


def is_trading_day(date_str: str) -> bool:
    try:
        date_obj = datetime.strptime(date_str, "%Y-%m-%d")
        if date_obj.weekday() >= 5:
            return False
    except Exception:
        return False

    try:
        import urllib.request
        req = urllib.request.Request(
            "https://qt.gtimg.cn/q=sh000001",
            headers={"User-Agent": "Mozilla/5.0"},
        )
        with urllib.request.urlopen(req, timeout=5) as resp:
            content = resp.read().decode("gbk", errors="replace")
        for line in content.split(";"):
            if "sh000001" in line:
                parts = line.split("~")
                if len(parts) > 30:
                    mkt_str = parts[30].strip()[:8]
                    market_date = f"{mkt_str[:4]}-{mkt_str[4:6]}-{mkt_str[6:8]}"
                    return market_date == date_str
                break
        return True  # API 异常时保守：工作日即为交易日
    except Exception:
        return True


def load_cron_state() -> dict:
    state_file = SIM_DIR / "paper_cron_state.json"
    if state_file.exists():
        return json.loads(state_file.read_text(encoding="utf-8"))
    return {}


def save_cron_state(data: dict) -> None:
    SIM_DIR.mkdir(parents=True, exist_ok=True)
    (SIM_DIR / "paper_cron_state.json").write_text(
        json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8"
    )


def run_update() -> dict:
    cmd = [sys.executable, str(SIM_DIR / "paper_trading.py"), "update"]
    proc = subprocess.run(cmd, cwd=str(ROOT), capture_output=True, text=True)
    return {
        "cmd": " ".join(cmd),
        "returncode": proc.returncode,
        "stdout": proc.stdout,
        "stderr": proc.stderr,
    }


def load_paper_state() -> dict | None:
    if not STATE_FILE.exists():
        return None
    return json.loads(STATE_FILE.read_text(encoding="utf-8"))


def build_summary(state: dict) -> str:
    """构建可读摘要"""
    nav = state.get("nav", 0)
    init = state.get("initial_capital", 1)
    ret = (nav / init - 1) * 100
    regime = state.get("current_regime", "?").upper()
    pos_count = len(state.get("positions", []))
    pos_ratio = state.get("position_ratio", 0) * 100

    emoji = {"RISK_ON": "🟢", "NEUTRAL": "🟡", "RISK_OFF": "🟠", "PANIC": "🔴"}
    re = emoji.get(regime, "")

    lines = [
        f"📊 混合策略模拟盘 {state.get('last_update','')}  {re} {regime}",
        f"净值: ¥{nav:,.0f}  ({ret:+.2f}%)  |  仓位: {pos_ratio:.0f}%  |  持仓: {pos_count}只",
    ]

    # Top 3 盈亏
    positions = state.get("positions", [])
    if positions:
        lines.append("")
        for pos in positions[:5]:
            cp = pos.get("current_price", pos.get("cost_price", 0))
            pnl = (cp / pos["cost_price"] - 1) * 100
            ch = "📈" if pnl > 0 else "📉" if pnl < 0 else "➖"
            lines.append(
                f"{ch} {pos['symbol']} {pos['name']} {pnl:+.1f}% [{pos['channel']}]"
            )
    return "\n".join(lines)


def main():
    parser = argparse.ArgumentParser(description="模拟盘盘后自动更新")
    parser.add_argument("--start", default="15:00")
    parser.add_argument("--end", default="17:00")
    parser.add_argument("--force", action="store_true")
    parser.add_argument("--summary", action="store_true", help="仅输出摘要不更新")
    parser.add_argument(
        "--emit-skip-json",
        action="store_true",
        help="输出 skip JSON（静默跳过时）",
    )
    args = parser.parse_args()

    now = now_shanghai()
    date_str = now.strftime("%Y-%m-%d")
    hhmm = now.strftime("%H:%M")

    # 摘要模式
    if args.summary:
        state = load_paper_state()
        if state:
            print(build_summary(state))
        else:
            print("❌ 模拟盘未初始化")
        return

    # 防重复
    cron_state = load_cron_state()
    if cron_state.get("last_run_date") == date_str and not args.force:
        if args.emit_skip_json:
            print(json.dumps(
                {"status": "skip", "reason": "already_run_today", "date": date_str},
                ensure_ascii=False,
            ))
        return

    # 交易日检查
    if not args.force and not is_trading_day(date_str):
        if args.emit_skip_json:
            print(json.dumps(
                {"status": "skip", "reason": "non_trading_day", "date": date_str},
                ensure_ascii=False,
            ))
        return

    # 时间窗口检查
    if not args.force:
        if not (args.start <= hhmm <= args.end):
            if args.emit_skip_json:
                print(json.dumps(
                    {
                        "status": "skip",
                        "reason": "outside_window",
                        "now": hhmm,
                        "window": [args.start, args.end],
                    },
                    ensure_ascii=False,
                ))
            return

    # 执行
    result = run_update()
    state = load_paper_state()

    summary = build_summary(state) if state else "模拟盘更新完成（无状态）"

    output = {
        "status": "ok" if result["returncode"] == 0 else "error",
        "date": date_str,
        "time": hhmm,
        "summary": summary,
        "nav": state.get("nav") if state else None,
        "return_pct": round((state["nav"] / state["initial_capital"] - 1) * 100, 2) if state else None,
        "regime": state.get("current_regime") if state else None,
        "result": result,
    }
    print(json.dumps(output, ensure_ascii=False, indent=2))

    # 保存 cron 状态
    save_cron_state({"last_run_date": date_str, "last_summary": summary})


if __name__ == "__main__":
    main()

